"use client";

import { useState, useCallback } from "react";
import { motion, useMotionValue, useTransform, animate } from "framer-motion";
import Image from "next/image";

export interface ImageRevealProps {
  src: string;
  alt: string;
  width?: number;
  height?: number;
  /** Stripe angle in degrees */
  stripeAngle?: number;
  /** Stripe width in px */
  stripeWidth?: number;
  /** Primary stripe color */
  stripeColor?: string;
  /** Secondary stripe color */
  stripeBg?: string;
  /** Trigger mode */
  trigger?: "hover" | "click";
  className?: string;
}

export function ImageReveal({
  src,
  alt,
  width = 360,
  height = 480,
  stripeAngle = -55,
  stripeWidth = 20,
  stripeColor = "#0f172a",
  stripeBg = "#1e293b",
  trigger = "hover",
  className = "",
}: ImageRevealProps) {
  const [revealed, setRevealedState] = useState(false);
  const clipProgress = useMotionValue(1); // 1 = fully masked, 0 = revealed

  // clipPath goes from "polygon(100% 0%,100% 0%,100% 100%,100% 100%)"
  // to "polygon(0% 0%,100% 0%,100% 100%,0% 100%)"
  const clipPath = useTransform(
    clipProgress,
    [0, 1],
    [
      "polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%)",
      "polygon(100% 0%, 100% 0%, 100% 100%, 100% 100%)",
    ]
  );

  const reveal = useCallback(() => {
    animate(clipProgress, 0, { duration: 0.7, ease: [0.22, 1, 0.36, 1] });
    setRevealedState(true);
  }, [clipProgress]);

  const conceal = useCallback(() => {
    animate(clipProgress, 1, { duration: 0.5, ease: [0.4, 0, 0.6, 1] });
    setRevealedState(false);
  }, [clipProgress]);

  const handlers =
    trigger === "hover"
      ? { onMouseEnter: reveal, onMouseLeave: conceal }
      : {
          onClick: () => (revealed ? conceal() : reveal()),
        };

  return (
    <div
      className={`relative overflow-hidden rounded-2xl cursor-pointer select-none ${className}`}
      style={{ width, height }}
      {...handlers}
    >
      {/* Base image */}
      <Image
        src={src}
        alt={alt}
        fill
        className="object-cover"
        sizes={`${width}px`}
        priority
      />

      {/* Animated gradient mask overlay */}
      <motion.div
        className="absolute inset-0 pointer-events-none"
        style={{
          background: `repeating-linear-gradient(
            ${stripeAngle}deg,
            ${stripeColor} 0px,
            ${stripeColor} ${stripeWidth}px,
            ${stripeBg} ${stripeWidth}px,
            ${stripeBg} ${stripeWidth * 2}px
          )`,
          clipPath,
          willChange: "clip-path",
        }}
      />

      {/* Subtle top-left shine */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          background:
            "linear-gradient(135deg, rgba(255,255,255,0.06) 0%, transparent 50%)",
        }}
      />

      {/* Hint label */}
      <motion.span
        className="absolute bottom-4 right-4 text-xs font-medium tracking-widest uppercase"
        style={{ color: "rgba(255,255,255,0.5)" }}
        animate={{ opacity: revealed ? 0 : 1 }}
        transition={{ duration: 0.3 }}
      >
        {trigger === "hover" ? "hover" : "tap"} to reveal
      </motion.span>
    </div>
  );
}

image-stack.code:
"use client";

import { useRef, useState, useCallback } from "react";
import {
  motion,
  useMotionValue,
  useTransform,
  animate,
  type PanInfo,
} from "framer-motion";
import Image from "next/image";

export interface StackCard {
  /** Image URL */
  src: string;
  /** Alt text */
  alt: string;
  /** Optional label shown on the top card */
  label?: string;
}

export interface ImageStackProps {
  /** Array of cards to display */
  cards: StackCard[];
  /** Card width in px (default: 260) */
  width?: number;
  /** Card height in px (default: 340) */
  height?: number;
  /** Px threshold for a swipe to count as a dismiss (default: 100) */
  dismissThreshold?: number;
  /** Called when a card is dismissed (index in original array) */
  onDismiss?: (card: StackCard, index: number) => void;
  /** Container class name */
  className?: string;
}

function StackCardItem({
  card,
  index,
  total,
  onDismiss,
  width,
  height,
  dismissThreshold,
}: {
  card: StackCard;
  index: number; // 0 = top
  total: number;
  onDismiss: () => void;
  width: number;
  height: number;
  dismissThreshold: number;
}) {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  // Back-cards rest rotation / vertical offset
  const restRot = [-6, -2.5, 1][index] ?? -8 + index * 2;
  const restTy = [0, 6, 12][index] ?? index * 6;
  const zIndex = total - index;

  // Rotate card as it's dragged (top card only)
  const rotate = useTransform(x, [-200, 200], [-18, 18]);

  // Opacity fades when flung
  const opacity = useTransform(
    x,
    [-dismissThreshold * 1.5, -dismissThreshold, 0, dismissThreshold, dismissThreshold * 1.5],
    [0, 1, 1, 1, 0]
  );

  const isTop = index === 0;

  const handleDragEnd = useCallback(
    (_: unknown, info: PanInfo) => {
      const dist = Math.sqrt(info.offset.x ** 2 + info.offset.y ** 2);
      if (dist > dismissThreshold) {
        const angle = Math.atan2(info.offset.y, info.offset.x);
        animate(x, Math.cos(angle) * 600, { duration: 0.35, ease: "easeIn" });
        animate(y, Math.sin(angle) * 600, { duration: 0.35, ease: "easeIn" });
        setTimeout(onDismiss, 340);
      } else {
        animate(x, 0, { type: "spring", stiffness: 300, damping: 25 });
        animate(y, 0, { type: "spring", stiffness: 300, damping: 25 });
      }
    },
    [x, y, dismissThreshold, onDismiss]
  );

  return (
    <motion.div
      className="absolute rounded-2xl overflow-hidden shadow-2xl"
      style={{
        width,
        height,
        x: isTop ? x : 0,
        y: isTop ? y : 0,
        rotate: isTop ? rotate : restRot,
        opacity: isTop ? opacity : 1,
        zIndex,
        translateY: isTop ? 0 : restTy,
        cursor: isTop ? "grab" : "default",
        top: 0,
        left: 0,
        willChange: "transform",
        boxShadow:
          "0 20px 60px rgba(0,0,0,0.25), 0 4px 16px rgba(0,0,0,0.12)",
      }}
      drag={isTop}
      dragConstraints={{ left: -400, right: 400, top: -400, bottom: 400 }}
      dragElastic={0.85}
      whileDrag={{ cursor: "grabbing", scale: 1.03 }}
      onDragEnd={isTop ? handleDragEnd : undefined}
    >
      <Image
        src={card.src}
        alt={card.alt}
        fill
        className="object-cover pointer-events-none"
        sizes={`${width}px`}
        draggable={false}
      />

      {/* Shine overlay */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          background:
            "linear-gradient(135deg, rgba(255,255,255,0.14) 0%, transparent 55%)",
        }}
      />

      {/* Label */}
      {card.label && isTop && (
        <motion.div
          className="absolute bottom-4 left-4 right-4 text-white text-sm font-medium"
          initial={{ opacity: 0, y: 8 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
        >
          {card.label}
        </motion.div>
      )}

      {/* Drag hint dots */}
      {isTop && (
        <motion.div
          className="absolute top-3 right-3 flex gap-1"
          initial={{ opacity: 0 }}
          animate={{ opacity: 0.5 }}
          transition={{ delay: 0.4 }}
        >
          {[0, 1, 2].map((d) => (
            <div
              key={d}
              className="w-1 h-1 rounded-full bg-white"
            />
          ))}
        </motion.div>
      )}
    </motion.div>
  );
}

export function ImageStack({
  cards: initialCards,
  width = 260,
  height = 340,
  dismissThreshold = 100,
  onDismiss,
  className = "",
}: ImageStackProps) {
  const [deck, setDeck] = useState(initialCards);
  const dismissedRef = useRef<StackCard[]>([]);

  const handleDismiss = useCallback(() => {
    setDeck((prev) => {
      const [top, ...rest] = prev;
      dismissedRef.current.push(top);
      onDismiss?.(top, initialCards.indexOf(top));

      // Cycle dismissed card to the bottom
      return [...rest, top];
    });
  }, [initialCards, onDismiss]);

  // Render only top 3 for performance
  const visible = deck.slice(0, 3);

  return (
    <div className={`flex flex-col items-center gap-4 ${className}`}>
      <div
        className="relative"
        style={{ width: width + 20, height: height + 20 }}
      >
        {/* Render back-to-front so top card receives events */}
        {[...visible].reverse().map((card, revI) => {
          const index = visible.length - 1 - revI;
          return (
            <StackCardItem
              key={card.src + index}
              card={card}
              index={index}
              total={visible.length}
              onDismiss={handleDismiss}
              width={width}
              height={height}
              dismissThreshold={dismissThreshold}
            />
          );
        })}
      </div>

      <p className="text-xs text-neutral-400 tracking-wider uppercase">
        drag top card to cycle
      </p>
    </div>
  );
}

image-parallax.code:
"use client";

import { useRef, useCallback, useEffect } from "react";
import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import Image from "next/image";

export interface ImageParallaxProps {
  /** Image source URL */
  src: string;
  /** Alt text */
  alt: string;
  /** Container width — any CSS value (default: "100%") */
  width?: string | number;
  /** Container height — any CSS value (default: 420) */
  height?: string | number;
  /** How many px the image travels on full mouse sweep */
  depth?: number;
  /** Diagonal grid stripe color */
  overlayColor?: string;
  /** Caption shown bottom-left */
  caption?: string;
  /** Sub-caption */
  subcaption?: string;
  /** Drive parallax from scroll instead of mouse (uses IntersectionObserver + scroll) */
  mode?: "mouse" | "scroll";
  /** Container class name */
  className?: string;
}

export function ImageParallax({
  src,
  alt,
  width = "100%",
  height = 420,
  depth = 40,
  overlayColor = "rgba(255,255,255,0.04)",
  caption,
  subcaption,
  mode = "mouse",
  className = "",
}: ImageParallaxProps) {
  const wrapRef = useRef<HTMLDivElement>(null);

  // Raw motion values 0→1 representing cursor/scroll position
  const rawX = useMotionValue(0.5);
  const rawY = useMotionValue(0.5);

  // Smooth spring followers
  const springX = useSpring(rawX, { stiffness: 60, damping: 20, mass: 0.5 });
  const springY = useSpring(rawY, { stiffness: 60, damping: 20, mass: 0.5 });

  // 3D Tilting transforms for container card (Yaw and Pitch rotation)
  const rotateX = useTransform(springY, [0, 1], [5, -5]);
  const rotateY = useTransform(springX, [0, 1], [-5, 5]);

  // Image translates in one direction
  const imgX = useTransform(springX, [0, 1], [depth / 2, -depth / 2]);
  const imgY = useTransform(springY, [0, 1], [depth / 2, -depth / 2]);

  // Overlay grid drifts the opposite direction (creates depth illusion)
  const overlayX = useTransform(springX, [0, 1], [-depth * 0.5, depth * 0.5]);
  const overlayY = useTransform(springY, [0, 1], [-depth * 0.5, depth * 0.5]);

  // Floating caption box drifts slightly for multi-layered depth
  const captionX = useTransform(springX, [0, 1], [-depth * 0.15, depth * 0.15]);
  const captionY = useTransform(springY, [0, 1], [-depth * 0.15, depth * 0.15]);

  // Subtle scale breathes on hover
  const scale = useSpring(1, { stiffness: 100, damping: 20 });

  const handleMouseMove = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (!wrapRef.current) return;
      const rect = wrapRef.current.getBoundingClientRect();
      rawX.set((e.clientX - rect.left) / rect.width);
      rawY.set((e.clientY - rect.top) / rect.height);
    },
    [rawX, rawY]
  );

  const handleMouseEnter = useCallback(() => scale.set(1.02), [scale]);
  const handleMouseLeave = useCallback(() => {
    rawX.set(0.5);
    rawY.set(0.5);
    scale.set(1);
  }, [rawX, rawY, scale]);

  // Scroll mode
  useEffect(() => {
    if (mode !== "scroll" || !wrapRef.current) return;
    const el = wrapRef.current;

    const onScroll = () => {
      const rect = el.getBoundingClientRect();
      const viewH = window.innerHeight;
      // progress: 0 when bottom enters view, 1 when top exits
      const progress =
        1 - Math.min(1, Math.max(0, rect.bottom / (viewH + rect.height)));
      rawY.set(progress);
    };

    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, [mode, rawY]);

  const containerStyle: React.CSSProperties = {
    width,
    height,
    position: "relative",
    overflow: "hidden",
    borderRadius: "1.25rem",
    border: "1px solid rgba(255, 255, 255, 0.08)",
  };

  return (
    <div style={{ perspective: "1200px", width }}>
      <motion.div
        ref={wrapRef}
        className={`group relative overflow-hidden ${className}`}
        style={{
          ...containerStyle,
          rotateX: mode === "mouse" ? rotateX : 0,
          rotateY: mode === "mouse" ? rotateY : 0,
          transformStyle: "preserve-3d",
          willChange: "transform",
        }}
        onMouseMove={mode === "mouse" ? handleMouseMove : undefined}
        onMouseEnter={mode === "mouse" ? handleMouseEnter : undefined}
        onMouseLeave={mode === "mouse" ? handleMouseLeave : undefined}
      >
        {/* Specular Inner Highlight Overlay Bevel */}
        <div className="absolute inset-0 rounded-[1.25rem] border border-transparent shadow-[inset_0_1px_1px_rgba(255,255,255,0.06),0_8px_32px_rgba(0,0,0,0.6)] pointer-events-none z-20" />

        {/* Parallax image — oversized so it can travel without gaps */}
        <motion.div
          className="absolute"
          style={{
            inset: `-${depth + 10}px`,
            x: imgX,
            y: imgY,
            scale,
            transformStyle: "preserve-3d",
            willChange: "transform",
          }}
        >
          <Image
            src={src}
            alt={alt}
            fill
            className="object-cover pointer-events-none"
            sizes="100vw"
            priority
          />
        </motion.div>

        {/* Repeating diagonal grid overlay — drifts opposite the image */}
        <motion.div
          className="absolute inset-0 pointer-events-none mix-blend-overlay opacity-15"
          style={{
            backgroundImage: `repeating-linear-gradient(
              45deg,
              ${overlayColor} 0px,
              ${overlayColor} 1px,
              transparent 1px,
              transparent 10px
            )`,
            backgroundSize: "14px 14px",
            x: overlayX,
            y: overlayY,
            willChange: "transform",
          }}
        />

        {/* Very subtle ambient bottom shadow gradient */}
        <div
          className="absolute inset-0 pointer-events-none z-10"
          style={{
            background:
              "linear-gradient(to top, rgba(0,0,0,0.25) 0%, rgba(0,0,0,0.02) 40%, transparent 100%)",
          }}
        />

        {/* Premium Frosted Glass Caption Panel */}
        {(caption || subcaption) && (
          <motion.div
            className="absolute bottom-6 left-6 right-6 p-4 rounded-xl border border-white/10 bg-black/25 backdrop-blur-md shadow-[0_4px_24px_rgba(0,0,0,0.4),inset_0_1px_0_rgba(255,255,255,0.05)] z-25 pointer-events-none"
            style={{
              x: mode === "mouse" ? captionX : 0,
              y: mode === "mouse" ? captionY : 0,
              transformStyle: "preserve-3d",
              willChange: "transform",
            }}
          >
            {caption && (
              <h4 className="text-white font-mono text-[9px] uppercase tracking-widest font-bold opacity-60 mb-1.5">
                {caption}
              </h4>
            )}
            {subcaption && (
              <p className="text-neutral-100 font-sans text-xs font-medium leading-relaxed">
                {subcaption}
              </p>
            )}
          </motion.div>
        )}
      </motion.div>
    </div>
  );
}

living-text.code:
"use client";

import { motion } from "framer-motion";
import { useEffect, useRef, useState, useId } from "react";
import { cn } from "../lib/utils";

export interface LivingTextProps {
  /** The text content to animate */
  text: string;
  /** Proximity radius of cursor influence in pixels */
  radius?: number;
  /** Movement offset strength in pixels */
  strength?: number;
  /** Proximity interaction mode */
  mode?: "repel" | "magnetize" | "stretch" | "rotate" | "ripple" | "all";
  /** Apply dynamic SVG turbulence/liquification filter */
  liquify?: boolean;
  /** Custom CSS class for the container */
  className?: string;
  /** Custom CSS class for each character */
  charClassName?: string;
}

export function LivingText({
  text,
  radius = 150,
  strength = 40,
  mode = "repel",
  liquify = false,
  className = "",
  charClassName = "",
}: LivingTextProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mouse, setMouse] = useState({ x: -9999, y: -9999 });
  const [containerForce, setContainerForce] = useState(0);
  const filterId = useId().replace(/:/g, "");

  useEffect(() => {
    const move = (e: MouseEvent) => {
      setMouse({ x: e.clientX, y: e.clientY });

      const el = containerRef.current;
      if (!el) return;

      const rect = el.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;

      const dx = centerX - e.clientX;
      const dy = centerY - e.clientY;
      const distance = Math.sqrt(dx * dx + dy * dy);

      const containerRadius = radius * 1.5;
      if (distance < containerRadius) {
        const force = (containerRadius - distance) / containerRadius;
        setContainerForce(force);
      } else {
        setContainerForce(0);
      }
    };

    window.addEventListener("mousemove", move);
    return () => {
      window.removeEventListener("mousemove", move);
    };
  }, [radius]);

  // Max scale distortion of 35px based on cursor proximity to container
  const filterScale = containerForce * 35;

  return (
    <div className="relative w-full flex justify-center py-8">
      {liquify && (
        <svg className="absolute w-0 h-0" aria-hidden="true" style={{ pointerEvents: "none" }}>
          <defs>
            <filter id={`liquify-filter-${filterId}`}>
              <feTurbulence
                type="fractalNoise"
                baseFrequency="0.015"
                numOctaves="3"
                result="noise"
              />
              <motion.feDisplacementMap
                in="SourceGraphic"
                in2="noise"
                scale={filterScale}
                xChannelSelector="R"
                yChannelSelector="G"
                animate={{ scale: filterScale }}
                transition={{
                  type: "spring",
                  stiffness: 100,
                  damping: 15,
                }}
              />
            </filter>
          </defs>
        </svg>
      )}
      <div
        ref={containerRef}
        className={cn(
          "flex flex-wrap justify-center gap-1 overflow-visible select-none",
          className
        )}
        style={{
          filter: liquify ? `url(#liquify-filter-${filterId})` : "none",
        }}
      >
        {text.split("").map((char, index) => (
          <Character
            key={`${char}-${index}`}
            char={char}
            mouse={mouse}
            radius={radius}
            strength={strength}
            mode={mode}
            charClassName={charClassName}
          />
        ))}
      </div>
    </div>
  );
}

interface CharacterProps {
  char: string;
  mouse: { x: number; y: number };
  radius: number;
  strength: number;
  mode: "repel" | "magnetize" | "stretch" | "rotate" | "ripple" | "all";
  charClassName: string;
}

function Character({
  char,
  mouse,
  radius,
  strength,
  mode,
  charClassName,
}: CharacterProps) {
  const ref = useRef<HTMLSpanElement>(null);

  const [offset, setOffset] = useState({
    x: 0,
    y: 0,
    scaleX: 1,
    scaleY: 1,
    rotate: 0,
  });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const rect = el.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;

    const dx = centerX - mouse.x;
    const dy = centerY - mouse.y;
    const distance = Math.sqrt(dx * dx + dy * dy);

    if (distance < radius) {
      const force = (radius - distance) / radius;
      const absDx = Math.abs(dx);
      const absDy = Math.abs(dy);

      let x = 0;
      let y = 0;
      let scaleX = 1;
      let scaleY = 1;
      let rotate = 0;

      // 1. Repel: Push away from cursor
      if (mode === "repel" || mode === "all") {
        x = (dx / distance) * force * strength;
        y = (dy / distance) * force * strength;
      }

      // 2. Magnetize: Pull toward cursor
      if (mode === "magnetize") {
        x = -(dx / distance) * force * strength;
        y = -(dy / distance) * force * strength;
      }

      // 3. Stretch: Scale X and Y depending on alignment axis
      if (mode === "stretch" || mode === "all") {
        const factor = mode === "all" ? 0.3 : 0.6;
        scaleX = 1 + (absDx / (distance || 1)) * force * factor;
        scaleY = 1 + (absDy / (distance || 1)) * force * factor;
      }

      // 4. Rotate: Shift angle relative to push direction
      if (mode === "rotate" || mode === "all") {
        const factor = mode === "all" ? 15 : 30;
        rotate = force * factor * (dx > 0 ? 1 : -1);
      }

      // 5. Ripple: Sinusoidal wave trigger based on distance and dynamic time
      if (mode === "ripple" || mode === "all") {
        const wave = Math.sin(distance * 0.05 - Date.now() * 0.01) * force * 15;
        y += wave;
      }

      setOffset({ x, y, scaleX, scaleY, rotate });
    } else {
      setOffset({ x: 0, y: 0, scaleX: 1, scaleY: 1, rotate: 0 });
    }
  }, [mouse, radius, strength, mode]);

  if (char === " ") {
    return <span className="w-4 md:w-6" aria-hidden="true" />;
  }

  return (
    <motion.span
      ref={ref}
      animate={{
        x: offset.x,
        y: offset.y,
        scaleX: offset.scaleX,
        scaleY: offset.scaleY,
        rotate: offset.rotate,
      }}
      transition={{
        type: "spring",
        stiffness: 180,
        damping: 12,
        mass: 0.8,
      }}
      className={cn(
        "inline-block cursor-default font-display font-black text-6xl md:text-8xl select-none will-change-transform text-white",
        charClassName
      )}
    >
      {char}
    </motion.span>
  );
}

