metallic-form.code:
"use client";

import React, { useRef, useState } from "react";
import { motion, AnimatePresence, useMotionValue, useSpring, useMotionTemplate } from "framer-motion";
import { ChromeInput } from "./ChromeInput";
import { ChromeSelect } from "./ChromeSelect";
import { BrushedTitaniumButton } from "./BrushedTitaniumButton";
import { cn } from "../lib/utils";

export interface FormField {
  name: string;
  label: string;
  type?: "text" | "email" | "password" | "textarea" | "select";
  placeholder?: string;
  required?: boolean;
  options?: { value: string; label: string }[];
  validation?: (value: string) => { valid: boolean; error?: string };
}

export interface MetallicFormProps {
  title?: string;
  subtitle?: string;
  fields: FormField[];
  onSubmit: (data: Record<string, string>) => Promise<void> | void;
  submitLabel?: string;
  className?: string;
}

interface FormError {
  [key: string]: string;
}

export function MetallicForm({
  title,
  subtitle,
  fields,
  onSubmit,
  submitLabel = "SUBMIT",
  className,
}: MetallicFormProps) {
  const [formData, setFormData] = useState<Record<string, string>>(
    fields.reduce((acc, field) => ({ ...acc, [field.name]: "" }), {})
  );
  const [errors, setErrors] = useState<FormError>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);

  // Track focused state for styling
  const [focusedField, setFocusedField] = useState<string | null>(null);
  const [hoveredField, setHoveredField] = useState<string | null>(null);
  const [typingFields, setTypingFields] = useState<Set<string>>(new Set());
  const [savedFields, setSavedFields] = useState<Set<string>>(new Set());
  const typingTimeoutsRef = useRef<Record<string, NodeJS.Timeout>>({});

  // Container spotlight coordinates
  const containerRef = useRef<HTMLDivElement>(null);
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);
  const springX = useSpring(mouseX, { stiffness: 80, damping: 25 });
  const springY = useSpring(mouseY, { stiffness: 80, damping: 25 });

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    mouseX.set(e.clientX - rect.left);
    mouseY.set(e.clientY - rect.top);
  };

  const spotlightBg = useMotionTemplate`radial-gradient(circle 400px at ${springX}px ${springY}px, rgba(255, 255, 255, 0.04), transparent)`;

  // Textarea spotlight coordinates (individual field level for high fidelity)
  const textareaMouseX = useMotionValue(0);
  const textareaMouseY = useMotionValue(0);
  const textareaSpringX = useSpring(textareaMouseX, { stiffness: 90, damping: 20 });
  const textareaSpringY = useSpring(textareaMouseY, { stiffness: 90, damping: 20 });

  const handleTextareaMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    textareaMouseX.set(e.clientX - rect.left);
    textareaMouseY.set(e.clientY - rect.top);
  };

  const handleFieldChange = (fieldName: string, value: string) => {
    setFormData((prev) => ({ ...prev, [fieldName]: value }));

    // Show typing indicator
    setTypingFields((prev) => {
      const newSet = new Set(prev);
      newSet.add(fieldName);
      return newSet;
    });

    // Clear existing timeout
    if (typingTimeoutsRef.current[fieldName]) {
      clearTimeout(typingTimeoutsRef.current[fieldName]);
    }

    // Set new timeout to hide typing indicator after user stops
    typingTimeoutsRef.current[fieldName] = setTimeout(() => {
      setTypingFields((prev) => {
        const newSet = new Set(prev);
        newSet.delete(fieldName);
        return newSet;
      });
    }, 1500);

    // Clear error when user starts typing
    if (errors[fieldName]) {
      setErrors((prev) => {
        const newErrors = { ...prev };
        delete newErrors[fieldName];
        return newErrors;
      });
    }
  };

  const handleFieldSave = (fieldName: string) => {
    if (formData[fieldName].trim()) {
      setSavedFields((prev) => {
        const newSet = new Set(prev);
        newSet.add(fieldName);
        return newSet;
      });
      setTypingFields((prev) => {
        const newSet = new Set(prev);
        newSet.delete(fieldName);
        return newSet;
      });
    } else {
      setSavedFields((prev) => {
        const newSet = new Set(prev);
        newSet.delete(fieldName);
        return newSet;
      });
    }
  };

  const handleFieldBlur = (fieldName: string) => {
    handleFieldSave(fieldName);
  };

  const validateForm = (): boolean => {
    const newErrors: FormError = {};

    fields.forEach((field) => {
      const value = formData[field.name] || "";

      // Check required
      if (field.required && !value.trim()) {
        newErrors[field.name] = "This field is required";
        return;
      }

      // Run custom validation
      if (field.validation && value) {
        const result = field.validation(value);
        if (!result.valid) {
          newErrors[field.name] = result.error || "Invalid input";
        }
      }
    });

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) return;

    setIsSubmitting(true);
    try {
      await onSubmit(formData);
      setSubmitSuccess(true);
      setFormData(fields.reduce((acc, field) => ({ ...acc, [field.name]: "" }), {}));
      setSavedFields(new Set());
      setTypingFields(new Set());
      setTimeout(() => setSubmitSuccess(false), 4000);
    } catch (error) {
      console.error("Form submission error:", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const textareaSpotlightBg = useMotionTemplate`radial-gradient(circle 120px at ${textareaSpringX}px ${textareaSpringY}px, rgba(255, 255, 255, 0.05), transparent)`;

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full max-w-2xl mx-auto rounded-xl overflow-hidden",
        className
      )}
      onMouseMove={handleMouseMove}
    >
      {/* Background spotlight layer */}
      <motion.div
        className="absolute inset-0 pointer-events-none"
        style={{ background: spotlightBg }}
      />

      {/* Base background - pitch black with subtle texture */}
      <div className="absolute inset-0 rounded-xl bg-black" />

      {/* Brushed texture overlay */}
      <div
        className="absolute inset-0 opacity-20 pointer-events-none rounded-xl"
        style={{
          backgroundImage:
            "repeating-linear-gradient(0deg, rgba(255,255,255,0.02) 0px, rgba(255,255,255,0.02) 1px, transparent 1px, transparent 2px)",
        }}
      />

      {/* Subtle border */}
      <div className="absolute inset-0 rounded-xl border border-neutral-800/50 pointer-events-none" />

      {/* Content */}
      <div className="relative z-10 p-8 md:p-12">
        {/* Header */}
        {(title || subtitle) && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
            className="mb-8"
          >
            {title && (
              <h2 className="text-3xl font-bold text-white font-mono uppercase tracking-widest mb-2">
                {title}
              </h2>
            )}
            {subtitle && (
              <p className="text-neutral-500 text-sm font-mono">{subtitle}</p>
            )}
            <div className="h-px bg-neutral-800/50 mt-4" />
          </motion.div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4">
            <AnimatePresence mode="wait">
              {fields.map((field, index) => {
                const isFullWidth = field.type === "textarea";
                return (
                  <motion.div
                    key={field.name}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -20 }}
                    transition={{ delay: index * 0.08, duration: 0.4 }}
                    className={cn("space-y-2", isFullWidth ? "md:col-span-2" : "col-span-1")}
                  >
                    {/* Field label */}
                    <div className="flex items-center justify-between gap-2">
                      <motion.label
                        className={cn(
                          "block text-xs uppercase tracking-widest font-mono transition-colors duration-300",
                          savedFields.has(field.name)
                            ? "text-neutral-400"
                            : focusedField === field.name
                            ? "text-neutral-200"
                            : errors[field.name]
                            ? "text-red-400"
                            : "text-neutral-600"
                        )}
                      >
                        {field.label}
                        {field.required && <span className="text-neutral-500 ml-1">*</span>}
                      </motion.label>

                      {/* Typing indicator */}
                      {typingFields.has(field.name) && (
                        <motion.div
                          initial={{ opacity: 0 }}
                          animate={{ opacity: 1 }}
                          exit={{ opacity: 0 }}
                          className="flex items-center gap-1"
                        >
                          <motion.div
                            animate={{ y: [0, -4, 0] }}
                            transition={{ duration: 0.6, repeat: Infinity, delay: 0 }}
                            className="w-1 h-1 rounded-full bg-neutral-500"
                          />
                          <motion.div
                            animate={{ y: [0, -4, 0] }}
                            transition={{ duration: 0.6, repeat: Infinity, delay: 0.2 }}
                            className="w-1 h-1 rounded-full bg-neutral-500"
                          />
                          <motion.div
                            animate={{ y: [0, -4, 0] }}
                            transition={{ duration: 0.6, repeat: Infinity, delay: 0.4 }}
                            className="w-1 h-1 rounded-full bg-neutral-500"
                          />
                        </motion.div>
                      )}
                    </div>

                    {/* Input field variants */}
                    {field.type === "textarea" ? (
                      <motion.div
                        className={cn(
                          "relative rounded-lg overflow-hidden border transition-all duration-300",
                          errors[field.name]
                            ? "border-red-500/40 shadow-[0_0_12px_rgba(239,68,68,0.1)]"
                            : focusedField === field.name
                            ? "border-neutral-500 shadow-[0_0_16px_rgba(255,255,255,0.06)]"
                            : hoveredField === field.name
                            ? "border-neutral-700"
                            : "border-neutral-800"
                        )}
                        onMouseEnter={() => {
                          setFocusedField(field.name);
                          setHoveredField(field.name);
                        }}
                        onMouseLeave={() => {
                          setFocusedField(null);
                          setHoveredField(null);
                        }}
                        onMouseMove={handleTextareaMouseMove}
                        style={{
                          backgroundImage: "linear-gradient(to bottom, #0a0a0c, #151518)",
                          boxShadow: "inset 0 1px 0 rgba(255, 255, 255, 0.05), 0 2px 8px rgba(0, 0, 0, 0.4)",
                        }}
                      >
                        {/* Brushed micro-lines texture inside textarea wrapper */}
                        <div
                          className="absolute inset-0 opacity-20 pointer-events-none mix-blend-overlay"
                          style={{
                            backgroundImage:
                              "repeating-linear-gradient(0deg, rgba(255,255,255,0.05) 0px, rgba(255,255,255,0.05) 1px, transparent 1px, transparent 2px)",
                          }}
                        />

                        {/* Spotlight overlay inside textarea wrapper */}
                        <motion.div
                          className="absolute inset-0 pointer-events-none"
                          animate={{ opacity: focusedField === field.name || hoveredField === field.name ? 1 : 0 }}
                          transition={{ duration: 0.3 }}
                          style={{ background: textareaSpotlightBg }}
                        />

                        <textarea
                          value={formData[field.name]}
                          onChange={(e) => handleFieldChange(field.name, e.target.value)}
                          onFocus={() => setFocusedField(field.name)}
                          onBlur={() => {
                            setFocusedField(null);
                            handleFieldBlur(field.name);
                          }}
                          placeholder={field.placeholder}
                          className={cn(
                            "relative z-10 w-full h-32 px-4 py-3 bg-transparent text-neutral-100 font-mono text-sm outline-none border-none resize-none",
                            "placeholder:text-neutral-700"
                          )}
                        />

                        {/* Bezel inner shadow */}
                        <div className="absolute inset-0 border border-transparent rounded-lg pointer-events-none shadow-[inset_0_1px_1px_rgba(255,255,255,0.04)]" />
                      </motion.div>
                    ) : field.type === "select" && field.options ? (
                      <div
                        onMouseEnter={() => {
                          setFocusedField(field.name);
                          setHoveredField(field.name);
                        }}
                        onMouseLeave={() => {
                          setFocusedField(null);
                          setHoveredField(null);
                        }}
                      >
                        <ChromeSelect
                          value={formData[field.name]}
                          options={field.options}
                          onChange={(e) => handleFieldChange(field.name, e.target.value)}
                          onFocus={() => setFocusedField(field.name)}
                          onBlur={() => {
                            setFocusedField(null);
                            handleFieldBlur(field.name);
                          }}
                          error={errors[field.name]}
                        />
                      </div>
                    ) : (
                      <div
                        onMouseEnter={() => {
                          setFocusedField(field.name);
                          setHoveredField(field.name);
                        }}
                        onMouseLeave={() => {
                          setFocusedField(null);
                          setHoveredField(null);
                        }}
                      >
                        <ChromeInput
                          type={field.type || "text"}
                          value={formData[field.name]}
                          onChange={(e) => handleFieldChange(field.name, e.target.value)}
                          onFocus={() => setFocusedField(field.name)}
                          onBlur={() => {
                            setFocusedField(null);
                            handleFieldBlur(field.name);
                          }}
                          placeholder={field.placeholder}
                          error={errors[field.name]}
                        />
                      </div>
                    )}

                    {/* Field error */}
                    <AnimatePresence>
                      {errors[field.name] && (
                        <motion.p
                          initial={{ opacity: 0, y: -10 }}
                          animate={{ opacity: 1, y: 0 }}
                          exit={{ opacity: 0, y: -10 }}
                          transition={{ duration: 0.2 }}
                          className="text-xs text-red-400 font-mono mt-1"
                        >
                          {errors[field.name]}
                        </motion.p>
                      )}
                    </AnimatePresence>
                  </motion.div>
                );
              })}
            </AnimatePresence>
          </div>

          {/* Submit button with loading state */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: fields.length * 0.08, duration: 0.4 }}
            className="pt-6 border-t border-neutral-800/50"
          >
            <button
              type="submit"
              disabled={isSubmitting}
              className="w-full relative group cursor-pointer border-none bg-transparent p-0 outline-none"
            >
              <BrushedTitaniumButton className="w-full h-12 uppercase tracking-widest font-mono text-sm">
                {isSubmitting ? "PROCESSING..." : submitLabel}
              </BrushedTitaniumButton>
            </button>
          </motion.div>
        </form>

        {/* Success message */}
        <AnimatePresence>
          {submitSuccess && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ type: "spring", stiffness: 100, damping: 20 }}
              className="mt-6 p-4 rounded-lg bg-neutral-900/40 border border-neutral-800/80 shadow-[0_4px_12px_rgba(0,0,0,0.5)]"
            >
              <p className="text-sm font-mono text-neutral-300 text-center flex items-center justify-center gap-2">
                <span className="text-emerald-500">✓</span> Form submitted successfully
              </p>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}

anisotropic-knob.code:
"use client";

import React, { useRef, useState, useEffect } from "react";
import { motion } from "framer-motion";
import { cn } from "../lib/utils";

export interface AnisotropicKnobProps {
  variant?: "slider" | "infinite";
  min?: number;
  max?: number;
  value?: number;
  onChange?: (value: number) => void;
  defaultValue?: number;
  step?: number;
  size?: number;
  label?: string;
  className?: string;
}

let audioCtx: AudioContext | null = null;

function playClickSound() {
  if (typeof window === "undefined") return;
  try {
    const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContextClass) return;

    if (!audioCtx) {
      audioCtx = new AudioContextClass();
    }

    if (audioCtx.state === "suspended") {
      audioCtx.resume();
    }

    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();

    osc.type = "sine";
    osc.frequency.setValueAtTime(1200, audioCtx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(80, audioCtx.currentTime + 0.012);

    gain.gain.setValueAtTime(0.04, audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, audioCtx.currentTime + 0.012);

    osc.connect(gain);
    gain.connect(audioCtx.destination);

    osc.start();
    osc.stop(audioCtx.currentTime + 0.012);
  } catch (e) {
    // Fail silently if context is blocked
  }
}

export const AnisotropicKnob = React.forwardRef<HTMLDivElement, AnisotropicKnobProps>(
  (
    {
      variant = "slider",
      min = 0,
      max = 100,
      value: controlledValue,
      onChange,
      defaultValue,
      step = 1,
      size = 112,
      label,
      className,
    },
    ref
  ) => {
    // Uncontrolled state fallback
    const [localValue, setLocalValue] = useState(defaultValue ?? (variant === "slider" ? min : 0));
    const activeValue = controlledValue !== undefined ? controlledValue : localValue;

    // Track active rotation angle in degrees (centered at 12 o'clock = 0 deg)
    const [angle, setAngle] = useState(0);
    const isDragging = useRef(false);
    const prevAngleRef = useRef(0);
    const accumulatedAngleRef = useRef(0);
    const containerRef = useRef<HTMLDivElement>(null);

    const lastValueRef = useRef(activeValue);

    // Play click sound on snap changes
    useEffect(() => {
      if (activeValue !== lastValueRef.current) {
        playClickSound();
        lastValueRef.current = activeValue;
      }
    }, [activeValue]);

    // Sync angle with activeValue for bounded slider mode on external changes
    useEffect(() => {
      if (variant === "slider") {
        const progress = (activeValue - min) / (max - min);
        // Map [0, 1] progress to [-135, 135] degrees
        const newAngle = -135 + progress * 270;
        setAngle(newAngle);
        accumulatedAngleRef.current = newAngle;
      }
    }, [activeValue, min, max, variant]);

    // Handle computing angle from pointer coordinates relative to center
    const calculateAngle = (clientX: number, clientY: number) => {
      if (!containerRef.current) return 0;
      const rect = containerRef.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;

      const dx = clientX - centerX;
      const dy = clientY - centerY;

      // Radian where 3 o'clock is 0, 6 o'clock is PI/2, 12 o'clock is -PI/2
      const angleRad = Math.atan2(dy, dx);
      // Normalize so 12 o'clock is 0 degrees, clockwise increases
      let angleDeg = angleRad * (180 / Math.PI) + 90;

      // Restrict range to [-180, 180]
      if (angleDeg > 180) angleDeg -= 360;
      if (angleDeg < -180) angleDeg += 360;

      return angleDeg;
    };

    const handlePanStart = (_: any, info: any) => {
      isDragging.current = true;
      const clientX = info.point.x;
      const clientY = info.point.y;
      const startAngle = calculateAngle(clientX, clientY);
      prevAngleRef.current = startAngle;

      if (variant === "infinite") {
        // Initialize or preserve current accumulated angle
        accumulatedAngleRef.current = angle;
      }
    };

    const handlePan = (_: any, info: any) => {
      if (!isDragging.current) return;
      const clientX = info.point.x;
      const clientY = info.point.y;
      const currentAngle = calculateAngle(clientX, clientY);

      if (variant === "slider") {
        let targetAngle = currentAngle;

        // Handle snapping boundaries near the 90-degree gap at 6 o'clock (135 to 225 deg from start)
        // Angle range in slider is [-135, 135]
        if (targetAngle > 135 || targetAngle < -135) {
          // If cursor is in the bottom gap, snap to closest extreme
          if (targetAngle > 0) {
            targetAngle = 135;
          } else {
            targetAngle = -135;
          }
        }

        // Map angle [-135, 135] to progress [0, 1]
        const progress = (targetAngle - -135) / 270;
        let targetVal = min + progress * (max - min);

        // Snap to step resolution
        targetVal = Math.round(targetVal / step) * step;
        targetVal = Math.max(min, Math.min(max, targetVal));

        if (onChange) {
          onChange(targetVal);
        } else {
          setLocalValue(targetVal);
        }
      } else {
        // Infinite Mode: Track angle delta to accumulate unbounded rotations
        let delta = currentAngle - prevAngleRef.current;

        // Wrap around adjustments
        if (delta > 180) delta -= 360;
        if (delta < -180) delta += 360;

        accumulatedAngleRef.current += delta;
        prevAngleRef.current = currentAngle;
        setAngle(accumulatedAngleRef.current);

        // Value updates: 3.6 degrees = 1 unit change
        const targetVal = Math.round(accumulatedAngleRef.current / (360 / 100) / step) * step;
        if (onChange) {
          onChange(targetVal);
        } else {
          setLocalValue(targetVal);
        }
      }
    };

    const handlePanEnd = () => {
      isDragging.current = false;
    };

    // Keyboard accessibility support
    const handleKeyDown = (e: React.KeyboardEvent) => {
      const incrementKeys = ["ArrowUp", "ArrowRight"];
      const decrementKeys = ["ArrowDown", "ArrowLeft"];

      let nextValue = activeValue;
      if (incrementKeys.includes(e.key)) {
        e.preventDefault();
        nextValue = activeValue + step;
      } else if (decrementKeys.includes(e.key)) {
        e.preventDefault();
        nextValue = activeValue - step;
      }

      if (variant === "slider") {
        nextValue = Math.max(min, Math.min(max, nextValue));
      }

      if (nextValue !== activeValue) {
        if (onChange) {
          onChange(nextValue);
        } else {
          setLocalValue(nextValue);
        }
      }
    };

    // Ticks calculation
    const totalTicks = 24;
    const ticks = Array.from({ length: totalTicks });

    // Helper to check if a specific tick is active
    const isTickActive = (index: number) => {
      if (variant === "infinite") return false;

      // Map tick index to angle (spread over 270 degrees)
      const tickAngle = -135 + (index / (totalTicks - 1)) * 270;
      return tickAngle <= angle + 0.5; // active if less than current angle
    };

    return (
      <div className={cn("flex flex-col items-center justify-center select-none", className)}>
        {/* Label */}
        {label && (
          <span className="font-mono text-[9px] text-neutral-500 uppercase tracking-widest mb-3">
            {label}
          </span>
        )}

        {/* Dial wrapper */}
        <div
          ref={containerRef}
          style={{ width: size + 32, height: size + 32 }}
          className="relative flex items-center justify-center"
        >
          {/* Bezel Tick Rings */}
          <div className="absolute inset-0 pointer-events-none">
            {ticks.map((_, i) => {
              // Radial spread for ticks
              // Slider spans -135 to +135 deg, Infinite spans a full 360 deg
              const tickAngle =
                variant === "slider"
                  ? -135 + (i / (totalTicks - 1)) * 270
                  : (i / totalTicks) * 360;

              const active = isTickActive(i);

              return (
                <div
                  key={i}
                  className="absolute inset-0 flex items-start justify-center"
                  style={{ transform: `rotate(${tickAngle}deg)` }}
                >
                  <div
                    className={cn(
                      "w-[2px] h-[6px] rounded-full transition-all duration-300",
                      variant === "infinite"
                        ? "bg-neutral-800"
                        : active
                        ? "bg-white shadow-[0_0_6px_rgba(255,255,255,0.7)]"
                        : "bg-neutral-800"
                    )}
                    style={{ marginTop: "2px" }}
                  />
                </div>
              );
            })}
          </div>

          {/* Draggable Knob Dial */}
          <motion.div
            ref={ref as any}
            tabIndex={0}
            onKeyDown={handleKeyDown}
            onPanStart={handlePanStart}
            onPan={handlePan}
            onPanEnd={handlePanEnd}
            role="slider"
            aria-valuemin={variant === "slider" ? min : undefined}
            aria-valuemax={variant === "slider" ? max : undefined}
            aria-valuenow={activeValue}
            style={{
              width: size,
              height: size,
              cursor: isDragging.current ? "grabbing" : "grab",
            }}
            className="relative rounded-full border border-neutral-800 flex items-center justify-center outline-none focus-visible:ring-1 focus-visible:ring-neutral-500"
          >
            {/* Outer Beveled Highlight Ring */}
            <div className="absolute inset-0 rounded-full border border-transparent shadow-[inset_0_1px_1px_rgba(255,255,255,0.06),0_4px_16px_rgba(0,0,0,0.6)] pointer-events-none" />

            {/* Anisotropic sweep cylinder (rotating conic reflection) */}
            <div
              className="absolute inset-[1px] rounded-full"
              style={{
                background: `conic-gradient(from ${angle}deg, #09090b 0%, #d8d8d8 25%, #09090b 50%, #d8d8d8 75%, #09090b 100%)`,
              }}
            />

            {/* Micro-lines Texture Overlay */}
            <div
              className="absolute inset-[1px] opacity-15 mix-blend-overlay rounded-full pointer-events-none"
              style={{
                backgroundImage:
                  "repeating-radial-gradient(circle at center, rgba(255,255,255,0.08) 0px, rgba(255,255,255,0.08) 1px, transparent 1px, transparent 2px)",
              }}
            />

            {/* Rotating Marker LED Dot */}
            <div
              className="absolute inset-0 pointer-events-none"
              style={{ transform: `rotate(${angle}deg)` }}
            >
              <div
                className="absolute w-[5px] h-[5px] rounded-full bg-white shadow-[0_0_8px_rgba(255,255,255,0.9)]"
                style={{ top: "8%", left: "50%", transform: "translateX(-50%)" }}
              />
            </div>

            {/* Raised center cap */}
            <div
              className="absolute inset-[18%] rounded-full border border-neutral-900 shadow-[inset_0_1px_0_rgba(255,255,255,0.1),0_2px_8px_rgba(0,0,0,0.5)]"
              style={{
                backgroundImage: "radial-gradient(circle at 35% 35%, #252529 0%, #0e0e11 100%)",
              }}
            />

            {/* Bezel inner highlights */}
            <div className="absolute inset-0 rounded-full border border-white/5 pointer-events-none" />
          </motion.div>
        </div>

        {/* Value Readout */}
        <div className="mt-2 font-mono text-[11px] tabular-nums text-neutral-400">
          {variant === "slider" ? `${activeValue}` : `${activeValue > 0 ? "+" : ""}${activeValue}`}
        </div>
      </div>
    );
  }
);

AnisotropicKnob.displayName = "AnisotropicKnob";

