"use client";

import React, { useState, useRef, useEffect } from "react";
import { motion } from "framer-motion";
import { ChevronRight } from "lucide-react";

const cn = (...classes: any[]) => classes.filter(Boolean).join(" ");

const swordImageSrc = "data:image/png;base64,";

// Web Audio sound synthesizer for rubber-band tension & snap feedback
class SlingshotSynth {
  private ctx: AudioContext | null = null;
  private tensionOsc: OscillatorNode | null = null;
  private tensionGain: GainNode | null = null;

  constructor() {
    if (typeof window === "undefined") return;
  }

  private initCtx() {
    if (this.ctx) return;
    const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      this.ctx = new AudioContextClass();
    }
  }

  public startTension(tensionPercent: number) {
    try {
      this.initCtx();
      if (!this.ctx) return;

      if (!this.tensionOsc || !this.tensionGain) {
        this.tensionOsc = this.ctx.createOscillator();
        this.tensionGain = this.ctx.createGain();
        this.tensionOsc.type = "triangle";
        this.tensionGain.gain.setValueAtTime(0, this.ctx.currentTime);
        this.tensionOsc.connect(this.tensionGain);
        this.tensionGain.connect(this.ctx.destination);
        this.tensionOsc.start();
      }

      const freq = 60 + tensionPercent * 80;
      const vol = Math.min(0.04, tensionPercent * 0.04);

      this.tensionOsc.frequency.setTargetAtTime(freq, this.ctx.currentTime, 0.05);
      this.tensionGain.gain.setTargetAtTime(vol, this.ctx.currentTime, 0.05);
    } catch (e) {}
  }

  public stopTension() {
    try {
      if (this.tensionGain && this.ctx) {
        this.tensionGain.gain.setTargetAtTime(0, this.ctx.currentTime, 0.05);
      }
      setTimeout(() => {
        if (this.tensionOsc) {
          try {
            this.tensionOsc.stop();
            this.tensionOsc.disconnect();
          } catch (e) {}
          this.tensionOsc = null;
          this.tensionGain = null;
        }
      }, 100);
    } catch (e) {}
  }

  public playSnap() {
    try {
      this.initCtx();
      if (!this.ctx) return;

      const osc = this.ctx.createOscillator();
      const gain = this.ctx.createGain();
      osc.type = "sine";

      osc.frequency.setValueAtTime(1400, this.ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(90, this.ctx.currentTime + 0.14);

      gain.gain.setValueAtTime(0.08, this.ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.14);

      osc.connect(gain);
      gain.connect(this.ctx.destination);
      osc.start();
      osc.stop(this.ctx.currentTime + 0.16);

      const clickOsc = this.ctx.createOscillator();
      const clickGain = this.ctx.createGain();
      clickOsc.type = "triangle";
      clickOsc.frequency.setValueAtTime(3000, this.ctx.currentTime);
      clickOsc.frequency.exponentialRampToValueAtTime(400, this.ctx.currentTime + 0.015);
      clickGain.gain.setValueAtTime(0.03, this.ctx.currentTime);
      clickGain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.015);
      clickOsc.connect(clickGain);
      clickGain.connect(this.ctx.destination);
      clickOsc.start();
      clickOsc.stop(this.ctx.currentTime + 0.02);
    } catch (e) {}
  }
}

export function SlingshotChassis({ className = "" }: { className?: string }) {
  const [isOpen, setIsOpen] = useState(false);
  const [dragX, setDragX] = useState(0);
  const [innerDragX, setInnerDragX] = useState(0);
  const synthRef = useRef<SlingshotSynth | null>(null);

  // Click conflict management timestamp
  const lastSnapTime = useRef(0);

  // Drag physics states
  const isDragging = useRef(false);
  const startX = useRef(0);
  const currentDragX = useRef(0);
  const springAnimFrame = useRef<number | null>(null);

  // Inner card drag-to-close states
  const isInnerDragging = useRef(false);
  const innerStartX = useRef(0);
  const currentInnerDragX = useRef(0);
  const innerSpringFrame = useRef<number | null>(null);

  const helveticaFont = { fontFamily: "Helvetica Neue, Helvetica, Arial, sans-serif" };

  useEffect(() => {
    synthRef.current = new SlingshotSynth();
    return () => {
      synthRef.current?.stopTension();
    };
  }, []);

  // Spring release solver for cover card
  const runSpringWobble = (initialX: number) => {
    let x = initialX;
    let velocity = 0;
    const stiffness = 280;
    const damping = 12;
    const mass = 1;
    let lastT = performance.now();

    const solve = (now: number) => {
      const dt = Math.min(0.032, (now - lastT) / 1000);
      lastT = now;

      const springForce = -stiffness * x;
      const dampingForce = -damping * velocity;
      const acceleration = (springForce + dampingForce) / mass;

      velocity += acceleration * dt;
      x += velocity * dt;

      setDragX(x);

      if (Math.abs(x) < 0.15 && Math.abs(velocity) < 0.15) {
        setDragX(0);
        springAnimFrame.current = null;
        return;
      }

      springAnimFrame.current = requestAnimationFrame(solve);
    };

    springAnimFrame.current = requestAnimationFrame(solve);
  };

  // Spring solver for inner card release
  const runInnerSpringWobble = (initialX: number) => {
    let x = initialX;
    let velocity = 0;
    const stiffness = 280;
    const damping = 16;
    const mass = 1;
    let lastT = performance.now();

    const solve = (now: number) => {
      const dt = Math.min(0.032, (now - lastT) / 1000);
      lastT = now;

      const springForce = -stiffness * x;
      const dampingForce = -damping * velocity;
      const acceleration = (springForce + dampingForce) / mass;

      velocity += acceleration * dt;
      x += velocity * dt;

      setInnerDragX(x);

      if (Math.abs(x) < 0.15 && Math.abs(velocity) < 0.15) {
        setInnerDragX(0);
        innerSpringFrame.current = null;
        return;
      }

      innerSpringFrame.current = requestAnimationFrame(solve);
    };

    springAnimFrame.current = requestAnimationFrame(solve);
  };

  // 1. Drag Cover Card handlers (When closed)
  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (isOpen) return;
    if (springAnimFrame.current) {
      cancelAnimationFrame(springAnimFrame.current);
    }
    isDragging.current = true;
    startX.current = e.clientX;
    e.currentTarget.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!isDragging.current) return;
    const deltaX = e.clientX - startX.current;
    let currentX = Math.max(0, deltaX);

    const maxDrag = 180;
    if (currentX > 80) {
      const overflow = currentX - 80;
      currentX = 80 + (maxDrag - 80) * (1 - Math.exp(-overflow / 120));
    }

    currentDragX.current = currentX;
    setDragX(currentX);

    const tensionPercent = currentX / maxDrag;
    synthRef.current?.startTension(tensionPercent);
  };

  const handlePointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!isDragging.current) return;
    isDragging.current = false;
    e.currentTarget.releasePointerCapture(e.pointerId);
    synthRef.current?.stopTension();

    const snapThreshold = 95;
    if (currentDragX.current >= snapThreshold) {
      synthRef.current?.playSnap();
      setIsOpen(true);
      lastSnapTime.current = Date.now();
    }

    runSpringWobble(currentDragX.current);
    currentDragX.current = 0;
  };

  // 2. Drag Inner Settings Card (When open - drag left to close)
  const handleInnerPointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!isOpen) return;
    if (innerSpringFrame.current) {
      cancelAnimationFrame(innerSpringFrame.current);
    }
    isInnerDragging.current = true;
    innerStartX.current = e.clientX;
    e.currentTarget.setPointerCapture(e.pointerId);
  };

  const handleInnerPointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!isInnerDragging.current) return;
    const deltaX = e.clientX - innerStartX.current;
    let currentX = Math.min(0, deltaX);

    const maxDrag = -180;
    if (currentX < -60) {
      const overflow = currentX + 60;
      currentX = -60 + (maxDrag + 60) * (1 - Math.exp(overflow / 120));
    }

    currentInnerDragX.current = currentX;
    setInnerDragX(currentX);

    const tensionPercent = Math.abs(currentX) / 180;
    synthRef.current?.startTension(tensionPercent);
  };

  const handleInnerPointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!isInnerDragging.current) return;
    isInnerDragging.current = false;
    e.currentTarget.releasePointerCapture(e.pointerId);
    synthRef.current?.stopTension();

    const closeThreshold = -60;
    if (currentInnerDragX.current <= closeThreshold) {
      synthRef.current?.playSnap();
      setIsOpen(false);
      setInnerDragX(0);
      lastSnapTime.current = Date.now();
    } else {
      runInnerSpringWobble(currentInnerDragX.current);
    }
    currentInnerDragX.current = 0;
  };

  const handleCoverClick = () => {
    if (Date.now() - lastSnapTime.current < 200) return;

    if (isOpen && !isInnerDragging.current) {
      synthRef.current?.playSnap();
      setIsOpen(false);
    }
  };

  // Rigid cover card remains at x = 0
  const coverX = isOpen ? 0 : dragX;

  // Custom long/heavy transition for the closing retraction phase
  const innerTransition = isInnerDragging.current
    ? { type: "just" as const }
    : isOpen
    ? { type: "spring", stiffness: 150, damping: 18 }
    : { type: "spring", stiffness: 45, damping: 24, mass: 1.5 }; // Slower, heavier glide-back transition

  return (
    <div className={cn("relative w-[300px] h-[380px] overflow-visible", className)}>

      {/* Background shadow */}
      <div className="absolute inset-0 rounded-2xl bg-black/60 shadow-[0_50px_100px_-20px_rgba(0,0,0,0.95)] pointer-events-none z-0" />

      {/* Main Cover Card (Underneath when open, zIndex 20; on top when closed, zIndex 30) */}
      <motion.div
        onPointerDown={isOpen ? undefined : handlePointerDown}
        onPointerMove={isOpen ? undefined : handlePointerMove}
        onPointerUp={isOpen ? undefined : handlePointerUp}
        onClick={handleCoverClick}
        animate={{ x: coverX }}
        transition={isDragging.current ? { type: "just" } : { type: "spring", stiffness: 150, damping: 18 }}
        style={{
          zIndex: isOpen ? 20 : 30,
          boxShadow: "inset 0 1px 0 rgba(255,255,255,0.08), 0 8px 24px rgba(0,0,0,0.8)",
          cursor: isOpen ? "pointer" : "grab",
        }}
        className="absolute inset-0 rounded-2xl bg-gradient-to-br from-[#131317] to-[#0a0a0d] border border-white/10 p-6 flex flex-col justify-between select-none"
      >
        <div className="h-6" />

        {/* Dynamic state label */}
        <div className="w-full flex flex-col items-center gap-2 py-4">
          {dragX > 10 ? (
            <div className="flex flex-col items-center">
              <span
                style={helveticaFont}
                className="text-[8px] text-white/40 tracking-widest animate-pulse uppercase font-semibold"
              >
                RELEASE TO SNAP
              </span>
              <span
                style={helveticaFont}
                className="text-[16px] text-white font-black mt-1"
              >
                {Math.round((dragX / 95) * 100)}%
              </span>
            </div>
          ) : (
            <div className="flex flex-col items-center gap-1.5">
              <ChevronRight className="w-4 h-4 text-neutral-400 animate-bounce" />
              <span
                style={helveticaFont}
                className="text-[8px] text-neutral-500 tracking-widest uppercase font-semibold text-center px-2"
              >
                {isOpen ? "CLICK LEFT TAB TO CLOSE" : "DRAG COVER TO SLINGSHOT"}
              </span>
            </div>
          )}
        </div>

        <div className="h-6" />
      </motion.div>

      {/* FRONT LAYER: Telemetry Settings Card (Slides on top when open at zIndex 30, exits leftwards back to x = 0 underneath when closed) */}
      <motion.div
        onPointerDown={handleInnerPointerDown}
        onPointerMove={handleInnerPointerMove}
        onPointerUp={handleInnerPointerUp}
        animate={{
          x: isOpen ? 20 + innerDragX : 0,
          opacity: isOpen ? 1 : 0,
          scale: isOpen ? 1 : 0.92,
        }}
        transition={innerTransition}
        style={{
          pointerEvents: isOpen ? "auto" : "none",
          boxShadow: "0 25px 60px -10px rgba(0,0,0,0.9), inset 0 1px 1px rgba(255,255,255,0.05)",
          zIndex: isOpen ? 30 : 20, // resides on top when open, drops below cover card when closed
        }}
        className="absolute inset-0 w-[300px] h-[380px] bg-[#07070a] border border-neutral-900 rounded-2xl overflow-hidden cursor-grab active:cursor-grabbing select-none"
      >
        <img
          src={swordImageSrc}
          alt="Sword"
          className="w-full h-full object-cover pointer-events-none select-none"
        />
        {/* Vignette overlay */}
        <div
          className="absolute inset-0 pointer-events-none"
          style={{
            background: "radial-gradient(circle, transparent 35%, rgba(0, 0, 0, 0.82) 100%)",
          }}
        />
      </motion.div>
    </div>
  );
}

